131→
132→  const dynamicMatch = DYNAMIC_PATTERNS.find((entry) => entry.test(normalized));
133→  if (dynamicMatch) {
134→    const seo = typeof dynamicMatch.seo === "function"
135→      ? dynamicMatch.seo(normalized)
136→      : dynamicMatch.seo;
137→    return { ...DEFAULT_SEO, ...seo };
138→  }
139→
140→  return { ...DEFAULT_SEO };
141→};
